+pub enum DifferentialPolicyClass {
+    /// Stable semantic mismatch on a supported surface.
+    RuntimeSemanticBug,
+    /// Lab model, mapping, or comparator bug.
+    LabModelOrMappingBug,
+    /// Required artifact schema or evidence is missing/malformed.
